mapper.select:
SELECT A.SEQ, A.RESUME_SEQ, A.EVS_STEP, GET_CODE_NAME(A.EVS_STEP, #{lang, jdbcType=VARCHAR}) AS EVS_STEP_NAME, A.EVS_GROUP, (SELECT CODE_NAME FROM EVS_PARAM WHERE CODE_NO = A.EVS_GROUP AND PARAM_TYPE = 'GROUP' AND RESUME_SEQ = A.RESUME_SEQ) AS EVS_GROUP_NAME, A.RULE_ID, GET_CODE_NAME(A.RULE_ID, #{lang, jdbcType=VARCHAR}) AS RULE_NAME, A.ACTIVITY, TO_CHAR(A.ORDERNO) AS ORDER_NO, TO_CHAR(A.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, GET_UPDATED_INFO(A.CREATED_BY) || ' ' || A.CREATED_IP AS CREATED_BY, TO_CHAR(A.UPDATE_DATE, 'YYYY-MM-DD HH24:MI') AS UPDATE_DATE, GET_UPDATED_INFO(A.UPDATED_BY) || ' ' || A.UPDATED_IP AS UPDATED_BY FROM EVS_AFFIRM_RULE A WHERE A.ACTIVITY != 2
AND A.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(A.SEQ)
